import UIKit

class PasswordResetViewController: UIViewController {
    var token: String?

    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Handle universal link
        handleUniversalLink()
    }
    
    private func handleUniversalLink() {
        guard let url = getURLFromScene() else { return }
        parseURL(url)
    }
    
    private func getURLFromScene() -> URL? {
        if let scene = UIApplication.shared.connectedScenes.first as? UIWindowScene, let window = scene.windows.first, let rootViewController = window.rootViewController as? UINavigationController, let topViewController = rootViewController.topViewController as? PasswordResetViewController {
            return UIApplication.shared.appdelegate?.scene(window.scene)?.coordinateSpace.convert(URLComponents(string: "https://myapp.com/reset-password?token=abc123")!.url!, to: topViewController.view)
        }
        return nil
    }
    
    private func parseURL(_ url: URL) {
        guard let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: true)?.queryItems else { return }
        
        for item in queryItems {
            if item.name == "token" {
                token = item.value
                break
            }
        }
        
        navigateToPasswordResetScreen()
    }
    
    private func navigateToPasswordResetScreen() {
        guard let token = token else { return }
        
        // Navigate to password reset screen with the token
        performSegue(withIdentifier: "showPasswordResetSegue", sender: token)
    }
